// TG-143: Fetch yesterday's completed jobs from Supabase
const supabaseUrl = 'https://lwtmvzhwekgdxkaisfra.supabase.co/rest/v1';
const supabaseKey = 'sb_publishable_DeX21ldoDKl3NyJeFZzR1w_eWBUkx-v';
const supabaseHeaders = {
  'apikey': supabaseKey,
  'Authorization': `Bearer ${supabaseKey}`
};

const now = new Date();
const yesterday20h = new Date(now.getTime() - 28 * 60 * 60 * 1000).toISOString();
const yesterday28h = new Date(now.getTime() - 20 * 60 * 60 * 1000).toISOString();

let completions = [];
try {
  completions = await this.helpers.httpRequest({
    method: 'GET',
    url: `${supabaseUrl}/jobber_email_events?event_type=eq.job_completed&created_at=gte.${yesterday20h}&created_at=lte.${yesterday28h}&select=customer_name,customer_address,service_type`,
    headers: supabaseHeaders
  });
} catch (e) {
  completions = [];
}

if (!Array.isArray(completions) || completions.length === 0) {
  return [{ json: { completions: [], _skip: true, message: 'No completed jobs yesterday' } }];
}

return [{ json: { completions } }];

// TG-143: Extract zip codes from completed job addresses
const data = $input.first().json;
if (data._skip) return [{ json: data }];

const completions = data.completions || [];
const zipPattern = /\b(\d{5})(-\d{4})?\b/;
const jobsByZip = {};

for (const job of completions) {
  const addr = job.customer_address || '';
  const match = addr.match(zipPattern);
  if (match) {
    const zip = match[1];
    if (!jobsByZip[zip]) jobsByZip[zip] = [];
    jobsByZip[zip].push({
      customerName: job.customer_name,
      address: addr,
      serviceType: job.service_type || 'lawn care'
    });
  }
}

const zipCodes = Object.keys(jobsByZip);
if (zipCodes.length === 0) {
  return [{ json: { _skip: true, message: 'No valid zip codes found' } }];
}

return [{ json: { jobsByZip, zipCodes } }];

// TG-143: Find neighbor leads in same zip codes, dedup by 30-day window
const data = $input.first().json;
if (data._skip) return [{ json: data }];

const supabaseUrl = 'https://lwtmvzhwekgdxkaisfra.supabase.co/rest/v1';
const supabaseKey = 'sb_publishable_DeX21ldoDKl3NyJeFZzR1w_eWBUkx-v';
const supabaseHeaders = {
  'apikey': supabaseKey,
  'Authorization': `Bearer ${supabaseKey}`
};

const thirtyDaysAgo = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000).toISOString();
const neighborLeads = [];

for (const zip of data.zipCodes) {
  const serviceType = data.jobsByZip[zip][0].serviceType;
  try {
    const leads = await this.helpers.httpRequest({
      method: 'GET',
      url: `${supabaseUrl}/leads?address=like.*${zip}*&status=neq.customer&select=id,name,phone,address,neighbor_sms_sent_at`,
      headers: supabaseHeaders
    });

    if (Array.isArray(leads)) {
      for (const lead of leads) {
        // Skip if no phone
        if (!lead.phone) continue;
        // Skip if neighbor SMS sent within last 30 days
        if (lead.neighbor_sms_sent_at && new Date(lead.neighbor_sms_sent_at) > new Date(thirtyDaysAgo)) continue;

        neighborLeads.push({
          leadId: lead.id,
          name: lead.name || 'Neighbor',
          phone: lead.phone,
          zip,
          serviceType
        });
      }
    }
  } catch (e) { /* continue */ }
}

if (neighborLeads.length === 0) {
  return [{ json: { _skip: true, message: 'No eligible neighbor leads found' } }];
}

return [{ json: { neighborLeads, zipCodes: data.zipCodes } }];

// TG-143: Build neighbor outreach SMS messages
const data = $input.first().json;
if (data._skip) return [{ json: data }];

const supabaseUrl = 'https://lwtmvzhwekgdxkaisfra.supabase.co/rest/v1';
const supabaseKey = 'sb_publishable_DeX21ldoDKl3NyJeFZzR1w_eWBUkx-v';
const supabaseHeaders = {
  'apikey': supabaseKey,
  'Authorization': `Bearer ${supabaseKey}`,
  'Content-Type': 'application/json'
};

const messages = [];

for (const lead of data.neighborLeads) {
  const firstName = lead.name.split(' ')[0];
  const messageBody = `Hi ${firstName}! TotalGuard was just servicing a property in your neighborhood with ${lead.serviceType}. We'd love to help your yard look amazing too! Free quotes: (608) 535-6057 or tgyardcare.com \u2014 TotalGuard`;

  messages.push({
    json: {
      to_phone: lead.phone,
      message_body: messageBody,
      workflow_name: 'TG-143',
      message_type: 'neighbor_outreach'
    }
  });

  // Update neighbor_sms_sent_at for dedup
  try {
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: `${supabaseUrl}/leads?id=eq.${lead.leadId}`,
      headers: { ...supabaseHeaders, 'Prefer': 'return=minimal' },
      body: { neighbor_sms_sent_at: new Date().toISOString() }
    });
  } catch (e) { /* continue */ }
}

return messages;

